// main.js — The Last Frequency
// Navigation, showBeat, applyBeat, loading sequence

const threadTag=document.getElementById('tt'),threadLabel=document.getElementById('tl'),autobar=document.getElementById('ab'),chBadge=document.getElementById('ch-badge');
function applyBeat(beat){if(beat.thread){const s=THREAD_STYLE[beat.thread];threadTag.style.background=s.color;threadLabel.textContent=s.label;threadLabel.style.color=s.color;autobar.style.background=s.color;threadLabel.style.opacity='.6';}else{threadTag.style.background='var(--gold)';threadLabel.textContent='';threadLabel.style.opacity='0';autobar.style.background='var(--gold)';}chBadge.textContent='Chapter '+beat.chapter+' \u2014 '+CHAPTER_META[beat.chapter].name;}
let lastAudioZone=null;
function updateAudio(idx){
  const chapNum = idx < 30 ? Math.floor(idx / 5) + 1 : null;
  const zone = CHAPTER_VIII_BEATS.has(idx) ? 'buried' : idx < 30 ? 'prequel' : 'surface';
  const zoneChanged = zone !== lastAudioZone;
  lastAudioZone = zone;
  if (zoneChanged) {
    if (zone === 'buried') {
      if (typeof fadeOut==='function') fadeOut(5);
      if (typeof stopPrequel==='function') stopPrequel(3);
      if (typeof startBuried==='function') startBuried(5);
    } else if (zone === 'prequel') {
      if (typeof stopBuried==='function') stopBuried(3);
      if (masterGain) { masterGain.gain.cancelScheduledValues(audioCtx.currentTime); masterGain.gain.linearRampToValueAtTime(0, audioCtx.currentTime + 3); }
      if (typeof startPrequel==='function') startPrequel(3);
    } else {
      if (typeof stopBuried==='function') stopBuried(5);
      if (typeof stopPrequel==='function') stopPrequel(3);
      if (typeof fadeIn==='function') fadeIn(5);
    }
  }
  if (zone === 'prequel' && chapNum !== null && typeof setPrequelChapter==='function') setPrequelChapter(chapNum);
}
let cur=0,autoTimer=null,rafBar=null,T=0,pendingCh=null;
const AUTO_MS=16000;
const titleEl=document.getElementById('bt'),textEl=document.getElementById('bx'),counter=document.getElementById('cc'),flash=document.getElementById('fl'),prog=document.getElementById('pg');
const chCard=document.getElementById('ch-card'),chCardNum=document.getElementById('ch-num'),chCardName=document.getElementById('ch-name'),chCardSub=document.getElementById('ch-sub');
let lastCh=null;
BEATS.forEach((b,i)=>{if(lastCh&&b.chapter!==lastCh){const sep=document.createElement('div');sep.className='dot-sep';prog.appendChild(sep);}const d=document.createElement('div');d.className='dot'+(b.thread?' t'+b.thread.toLowerCase():'');d.onclick=()=>goTo(i);prog.appendChild(d);lastCh=b.chapter;});
function updateDots(){let di=0;prog.querySelectorAll('.dot').forEach(d=>{d.classList.toggle('active',di===cur);di++;});}
function showBeat(idx){cur=idx;const beat=BEATS[idx];T=0;if(beat.type==='photo')startKB();applyBeat(beat);updateAudio(idx);titleEl.classList.remove('v');textEl.classList.remove('v');setTimeout(()=>{titleEl.textContent=beat.title;textEl.textContent=beat.text;textEl.className=(beat.chapter==='X'&&beat.thread==='C')?'signal':'';counter.textContent=beat.chapter+' \u00b7 '+(idx+1)+' / '+BEATS.length;updateDots();titleEl.classList.add('v');textEl.classList.add('v');},140);startBar();}
function startBar(){clearTimeout(autoTimer);if(rafBar)cancelAnimationFrame(rafBar);autobar.style.transition='none';autobar.style.width='0%';let t0=null;function step(ts){if(!t0)t0=ts;const p=Math.min((ts-t0)/AUTO_MS,1);autobar.style.width=(p*100)+'%';if(p<1)rafBar=requestAnimationFrame(step);else autoTimer=setTimeout(()=>{if(cur<BEATS.length-1)nav(1);},200);}rafBar=requestAnimationFrame(step);}
function flash2(cb){flash.classList.add('on');setTimeout(()=>{flash.classList.remove('on');cb();},440);}
function showChCard(ch,cb){const m=CHAPTER_META[ch];chCardNum.textContent='Chapter '+ch;chCardName.textContent=m.name;chCardSub.textContent=m.sub;const thr=document.getElementById('ch-threads');thr.innerHTML='';if(ch==='X'){[{color:'#9a7235',text:'Thread A \u2014 2031 \u00b7 Daan arrives.'},{color:'#5a9a5a',text:'Thread B \u2014 1947 \u00b7 Eleanor builds.'},{color:'#00aacc',text:'Thread C \u2014 4,600,000,000 BCE \u00b7 The signal.'}].forEach(t=>{const r=document.createElement('div');r.className='ch-lr';r.innerHTML='<div class="ch-ld" style="background:'+t.color+'"></div>'+t.text;thr.appendChild(r);});}pendingCh=cb;chCard.classList.add('show');}
function dismissChCard(){chCard.classList.remove('show');if(pendingCh){pendingCh();pendingCh=null;}}
function nav(dir){const n=cur+dir;if(n<0||n>=BEATS.length)return;clearTimeout(autoTimer);if(rafBar)cancelAnimationFrame(rafBar);if(dir===1&&n>0&&BEATS[n].chapter!==BEATS[n-1].chapter)flash2(()=>showChCard(BEATS[n].chapter,()=>flash2(()=>showBeat(n))));else flash2(()=>showBeat(n));}
function goTo(idx){if(idx===cur)return;clearTimeout(autoTimer);if(rafBar)cancelAnimationFrame(rafBar);flash2(()=>showBeat(idx));}
document.addEventListener('keydown',e=>{if(e.key==='ArrowRight'||e.key===' '){if(chCard.classList.contains('show'))dismissChCard();else nav(1);}if(e.key==='ArrowLeft')nav(-1);if(e.key==='Escape'&&chCard.classList.contains('show'))dismissChCard();if(e.key==='m'||e.key==='M')toggleMute();});
let audioKicked=false;
function kickAudio(){
  if(audioKicked)return; audioKicked=true;
  if(cur<30){
    // Chapters I–VI: start prequel engine only (shares audioCtx via initPrequel→initAudio)
    if(typeof startPrequel==='function') startPrequel(3);
  } else {
    startAudio();
    if(masterGain){masterGain.gain.cancelScheduledValues(audioCtx.currentTime);masterGain.gain.setValueAtTime(0,audioCtx.currentTime);masterGain.gain.linearRampToValueAtTime(currentVol,audioCtx.currentTime+4);}
  }
}
const _origDismiss=window.dismissChCard;window.dismissChCard=function(){kickAudio();if(_origDismiss)_origDismiss();}
let muted=false,currentVol=0.8;
function onVolChange(v){currentVol=v;if(!muted){setAudioVolume(v);if(buriedMaster&&buriedCtx&&buriedActive){buriedMaster.gain.cancelScheduledValues(buriedCtx.currentTime);buriedMaster.gain.linearRampToValueAtTime(v,buriedCtx.currentTime+1.5);}if(typeof prequelMaster!=='undefined'&&prequelMaster&&prequelActive){prequelMaster.gain.cancelScheduledValues(prequelCtx.currentTime);prequelMaster.gain.linearRampToValueAtTime(v,prequelCtx.currentTime+1.5);}}}
function toggleMute(){muted=!muted;const btn=document.getElementById('mute-btn');if(muted){if(typeof fadeOut==='function')fadeOut(0.5);if(buriedMaster&&buriedCtx){buriedMaster.gain.cancelScheduledValues(buriedCtx.currentTime);buriedMaster.gain.linearRampToValueAtTime(0,buriedCtx.currentTime+0.5);}if(typeof prequelMaster!=='undefined'&&prequelMaster&&prequelCtx){prequelMaster.gain.cancelScheduledValues(prequelCtx.currentTime);prequelMaster.gain.linearRampToValueAtTime(0,prequelCtx.currentTime+0.5);}btn.textContent='\u266a off';btn.classList.add('muted');}else{if(typeof fadeIn==='function')fadeIn(0.8);if(buriedMaster&&buriedCtx&&buriedActive){buriedMaster.gain.cancelScheduledValues(buriedCtx.currentTime);buriedMaster.gain.linearRampToValueAtTime(currentVol,buriedCtx.currentTime+0.8);}if(typeof prequelMaster!=='undefined'&&prequelMaster&&prequelCtx&&prequelActive){prequelMaster.gain.cancelScheduledValues(prequelCtx.currentTime);prequelMaster.gain.linearRampToValueAtTime(currentVol,prequelCtx.currentTime+0.8);}btn.textContent='\u266a on';btn.classList.remove('muted');}}
showChCard('I',()=>showBeat(0));


(function(){
  const screen   = document.getElementById('loading');
  const bgImg    = document.getElementById('loading-bg');
  const bar      = document.getElementById('loading-bar');
  const status   = document.getElementById('loading-status');
  const title    = document.getElementById('loading-title');
  const rule     = document.getElementById('loading-rule');
  const sub      = document.getElementById('loading-sub');
  const tagline  = document.getElementById('loading-tagline');
  const barWrap  = document.getElementById('loading-bar-wrap');

  // Show intro image immediately
  bgImg.src = 'data:image/png;base64,';
  bgImg.onload = function(){ bgImg.classList.add('show'); };

  // Stagger text animations
  setTimeout(()=>{ title.classList.add('show'); }, 400);
  setTimeout(()=>{ rule.classList.add('show'); sub.classList.add('show'); }, 1800);
  setTimeout(()=>{ tagline.classList.add('show'); }, 2600);
  setTimeout(()=>{ barWrap.classList.add('show'); status.classList.add('show'); }, 1200);

  // Preload story images
  const keys  = Object.keys(IMAGES);
  const total = keys.length;
  let loaded  = 0;

  function tick(){
    loaded++;
    const pct = Math.round((loaded / total) * 100);
    bar.style.width = pct + '%';
    status.textContent = pct + '% loaded';
    if(loaded >= total) done();
  }

  function done(){
    setTimeout(()=>{
      status.textContent = 'ready';
      // Brief pause so user can read the tagline, then fade out
      setTimeout(()=>{
        screen.classList.add('done');
        setTimeout(()=>{ screen.style.display = 'none'; }, 2200);
      }, 900);
    }, 300);
  }

  keys.forEach(k=>{
    const img     = new Image();
    img.onload    = tick;
    img.onerror   = tick;
    img.src       = IMAGES[k];
  });

  if(total === 0) done();
})();
